// SAFE Pattern 2 -- defensive Runnable wrapper
public class SafeRunnable implements Runnable {
    private final Runnable delegate;
    private final String taskName;

    @Override
    public void run() {
        try {
            delegate.run();
        } catch (Throwable t) {
            log.error("[TASK FAILURE] task={} thread={}",
                taskName, Thread.currentThread().getName(), t);
            Metrics.counter("executor.task.failure", "task", taskName).increment();
        }
    }
}
