// The bug -- equals defined, hashCode missing
public class OrderId {
    private final String id;
    public OrderId(String id) { this.id = id; }

    @Override
    public boolean equals(Object o) {
        if (!(o instanceof OrderId)) return false;
        return Objects.equals(id, ((OrderId) o).id);
    }
    // hashCode() NOT overridden -> uses Object.hashCode() (identity/address-based)
}

// Consequence
Map<OrderId, Order> cache = new HashMap<>();
OrderId key1 = new OrderId("ORD-001");
cache.put(key1, order);

OrderId key2 = new OrderId("ORD-001");
key1.equals(key2);   // true
cache.get(key2);     // null! Different hash -> different bucket -> equals never called

// The fix
public class OrderId {
    private final String id;
    public OrderId(String id) { this.id = id; }

    @Override
    public boolean equals(Object o) {
        if (!(o instanceof OrderId)) return false;
        return Objects.equals(id, ((OrderId) o).id);
    }

    @Override
    public int hashCode() {
        return Objects.hash(id);  // MUST use the SAME fields as equals()
    }
}

