// Fix lock contention -- upgrade from synchronized to ReadWriteLock
public class UserRegistry {
    private final ReadWriteLock rwLock = new ReentrantReadWriteLock();
    private final Map<String, User> users = new HashMap<>();

    public User get(String id) {
        rwLock.readLock().lock();          // Multiple concurrent readers allowed
        try { return users.get(id); }
        finally { rwLock.readLock().unlock(); }
    }

    public void put(String id, User u) {
        rwLock.writeLock().lock();         // Exclusive access for writers
        try { users.put(id, u); }
        finally { rwLock.writeLock().unlock(); }
    }
}

// Even better for most cases -- ConcurrentHashMap needs no explicit locking at all
private final ConcurrentHashMap<String, User> users = new ConcurrentHashMap<>();
public User get(String id) { return users.get(id); }  // Segment-level locking internally

