// RIGHT -- Resilience4j with full protection
@Configuration
public class ResilienceConfig {

    @Bean
    public CircuitBreakerConfig circuitBreakerConfig() {
        return CircuitBreakerConfig.custom()
            .slidingWindowSize(20)
            .failureRateThreshold(50.0f)       // OPEN after 50% failures
            .waitDurationInOpenState(Duration.ofSeconds(30))
            .permittedNumberOfCallsInHalfOpenState(3)
            .build();
    }

    @Bean
    public RetryConfig retryConfig() {
        return RetryConfig.custom()
            .maxAttempts(3)
            .intervalFunction(
                IntervalFunction.ofExponentialRandomBackoff(
                    500L,  // base delay
                    2.0,   // multiplier
                    0.5    // jitter factor: +/-50%
                )
            )
            .retryOnException(ex -> ex instanceof ConnectException
                                 || ex instanceof SocketTimeoutException)
            .build();
    }
}

@Service
public class PaymentService {

    @CircuitBreaker(name = "payment", fallbackMethod = "fallback")
    @Retry(name = "payment")
    public PaymentResult charge(PaymentRequest req) {
        // Idempotency key ensures the gateway treats retries as duplicates safely
        req.setIdempotencyKey(req.getOrderId() + "-" + req.getAttemptHash());
        return gateway.charge(req);
    }

    public PaymentResult fallback(PaymentRequest req, CallNotPermittedException ex) {
        // Circuit OPEN -- fail fast, do not hold any threads
        log.warn("Payment circuit open, queuing: {}", req.getOrderId());
        return PaymentResult.queued(req.getOrderId());
    }
}

