// Money type -- NEVER use double or float for financial values
public record Money(BigDecimal amount, Currency currency) {
    public Money {
        Objects.requireNonNull(amount, "amount required");
        Objects.requireNonNull(currency, "currency required");
        if (amount.scale() > 2)
            throw new IllegalArgumentException("Max 2 decimal places for INR");
        if (amount.compareTo(BigDecimal.ZERO) < 0)
            throw new IllegalArgumentException("Amount must be non-negative");
    }
    public Money add(Money other) {
        if (!currency.equals(other.currency)) throw new IllegalArgumentException("Currency mismatch");
        return new Money(amount.add(other.amount), currency);
    }
}

// Idempotent payment endpoint
@RestController
public class PaymentController {

    @PostMapping("/v1/payments")
    public ResponseEntity<PaymentResponse> initiatePayment(
            @RequestHeader("X-Idempotency-Key") String idempotencyKey,
            @Valid @RequestBody PaymentRequest request) {

        PaymentResult result = paymentService.processPayment(
            request.withIdempotencyKey(idempotencyKey));

        return switch (result.status()) {
            case SUCCESS -> ResponseEntity.ok(toResponse(result));
            case PENDING -> ResponseEntity.accepted().body(toResponse(result));
            case FAILED  -> ResponseEntity.unprocessableEntity().body(toResponse(result));
        };
    }
}

