@Scheduled(fixedDelay = 5000)
public void reconcilePendingPayments() {
    List<Payment> pending = paymentRepo.findPendingOlderThan(30, SECONDS);
    pending.forEach(p -> {
        NpciStatus status = npciAdapter.checkStatus(p.getRrn());
        if (status == SUCCESS) { completePayment(p); }
        else if (status == FAILED) { reversePayment(p); }
        // Still PENDING: leave for next cycle -- use exponential backoff for long waits
    });
}

