// Consumer with declarative retry topology
@Component
public class PaymentEventConsumer {

    @RetryableTopic(
        attempts = "4",   // 1 original + 3 retries across delay tiers
        backoff = @Backoff(delay = 500, multiplier = 2.0, maxDelay = 30_000),
        include = {RetryablePaymentException.class},   // Only retry these
        exclude = {InvalidPaymentException.class},     // DLQ immediately for these
        dltStrategy = DltStrategy.FAIL_ON_ERROR
    )
    @KafkaListener(topics = "payment-events",
                   groupId = "payment-processor",
                   concurrency = "10")  // 10 consumer threads for 10 partitions
    public void consume(PaymentEvent event,
                        @Header(KafkaHeaders.RECEIVED_PARTITION) int partition,
                        @Header(KafkaHeaders.OFFSET) long offset) {
        log.info("Processing txnId={} partition={} offset={}",
            event.getTxnId(), partition, offset);
        paymentProcessor.process(event);
    }

    @DltHandler
    public void handleDlt(PaymentEvent event,
                          @Header(KafkaHeaders.EXCEPTION_MESSAGE) String error) {
        log.error("DLQ: txnId={} reason={}", event.getTxnId(), error);
        alerting.critical("Payment in DLQ -- requires investigation", event.getTxnId());
        dlqRepo.save(new DlqRecord(event, error, Instant.now()));
    }
}

