// Distributed trace instrumentation
@PostMapping("/v1/payments")
public PaymentResponse pay(@RequestBody PaymentRequest req) {
    Span span = tracer.nextSpan().name("payment.initiate")
        .tag("txn.id",       req.getTxnId())
        .tag("payer.bank",   req.getPayerVpa().split("@")[1])
        .tag("payment.type", req.getType())
        .start();

    try (Tracer.SpanInScope ws = tracer.withSpan(span)) {
        return paymentService.process(req);
        // Trace context propagates automatically to:
        // - JDBC instrumentation (DB calls)
        // - Kafka header propagation (async events)
        // - HTTP header propagation (NPCI adapter, bank APIs)
    } finally {
        span.end();
    }
}
